embargo__title = TextObject(bs_BA="Alexa nije raspoloživa u ovoj državi.", cs_CZ="Alexa je v této zemi nedostupná.", da_DK="Alexa ikke tilgængelig i dette land.", de_DE="Alexa ist in diesem Land nicht verfügbar.", el_GR="Η Alexa δεν είναι διαθέσιμη σε αυτήν τη χώρα.", en_GB="Alexa is not available in this country.", es_ES="Alexa no está disponible en este país.", fi_FI="Alexa ei ole käytettävissä tässä maassa.", fr_FR="Alexa n'est pas disponible dans ce pays.", hr_HR="Alexa nije raspoloživa u ovoj zemlji.", hu_HU="Az Alexa ebben az országban nem áll rendelkezésre.", it_IT="Alexa non è disponibile in questo paese.", nl_NL="Alexa is in dit land niet beschikbaar.", no_NO="Alexa er ikke tilgjengelig i dette landet.", pl_PL="Funkcja Alexa jest w tym kraju niedostępna.", pt_PT="Alexa não está disponível neste país.", ro_RO="Alexa nu este disponibilă în această ţară.", ru_RU="Alexa в этой стране недоступна.", sk_SK="Alexa nie je v tejto krajine k dispozícii.", sl_SI="Alexa v tej državi ni na voljo.", sr_RS="Alexa nije dostupna u ovoj zemlji.", sv_SE="Alexa är inte tillgängligt i detta land.", tr_TR="Alexa bu ülkede mevcut değildir.", uk_UA="Alexa у цій країні недоступна.")
general_error__text = TextObject(bs_BA="Došlo je do greške. Pokušajte ponovo kasnije.", cs_CZ="Vyskytla se chyba. Zkuste to prosím znovu později.", da_DK="Fejl opstået. Forsøg igen senere.", de_DE="Es ist ein Fehler aufgetreten. Bitte versuche es später erneut.", el_GR="Προέκυψε σφάλμα. Προσπαθήστε πάλι αργότερα.", en_GB="An error has occurred. Please try again later.", es_ES="Se ha producido un error. Por favor, inténtelo de nuevo más tarde.", fi_FI="Tapahtui virhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur s'est produite. Veuillez réessayer ultérieurement.", hr_HR="Nastupila je greška. Pokušajte ponovno kasnije.", hu_HU="Hiba lépett fel. Kérünk, próbáld újra.", it_IT="Si è verificato un errore. Si prega di riprovare più tardi.", nl_NL="Er is een fout opgetreden. Probeer het later opnieuw.", no_NO="Det har oppstått en feil. Prøv igjen senere.", pl_PL="Wystąpił błąd. Proszę spróbować ponownie później.", pt_PT="Ocorreu uma falha. Por favor, volta a tentar.", ro_RO="A apărut o eroare. Reîncercaţi mai târziu.", ru_RU="Произошла ошибка. Пожалуйста, попытайтесь снова.", sk_SK="Vyskytla sa chyba. Prosím, pokúste sa o to znovu neskôr.", sl_SI="Prišlo je do napake. Poskusite znova.", sr_RS="Došlo je do greške. Pokušajte ponovo kasnije.", sv_SE="Ett fel har uppstått. Försök igen senare.", tr_TR="Bir hata oluştu. Lütfen daha sonra yeniden dene.", uk_UA="Сталася помилка. Повторіть спробу пізніше.")
