global_search__result_with_icon_as_link__secondary_text___invoke_alexa_sub_title = TextObject(bs_BA="Dodirnite ovdje i recite „Alexa“.", cs_CZ="Klepněte zde nebo řekněte \"Alexa\".", da_DK="Tryk her, eller sig \"Alexa\".", de_DE="Tippe hier oder sage \"Alexa\".", el_GR="Πατήστε εδώ ή πείτε \"Alexa\".", en_GB="Tap here or say \"Alexa\".", es_ES="Pulse aquí o diga \"Alexa\".", fi_FI="Kosketa tästä tai sano \"Alexa\".", fr_FR="Appuyez brièvement ici ou dites «Alexa».", hr_HR="Dodirni tu ili reci \"Alexa\".", hu_HU="Érintsd meg itt, vagy mondd azt, hogy „Alexa”.", it_IT="Toccare qui o dire \"Alexa\".", nl_NL="Tik hier of zeg \"Alexa\".", no_NO="Trykk her eller si «Alexa».", pl_PL="Dotknij tutaj albo powiedz „Alexa”.", pt_PT="Toca aqui ou diz \"Alexa\".", ro_RO="Apăsaţi aici sau rostiţi \"Alexa\".", ru_RU="Нажмите здесь или скажите «Alexa».", sk_SK="Krátko stlačte sem alebo vyslovte \"Alexa\".", sl_SI="Pritisnite tukaj ali recite \"Alexa\".", sr_RS="Pritisnite ovde ili recite „Alexa“.", sv_SE="Klicka här eller säg ”Alexa”.", tr_TR="Buraya dokun veya \"Alexa\" de.", uk_UA="Торкніться тут або скажіть «Alexa».")
