settings__location_sharing_subtitle_amzn = TextObject(de_DE="Teile den aktuellen Standort deines Fahrzeugs mit Alexa, um so bessere Ergebnisse für Restaurants in\nder Nähe, das lokale Wetter und andere Anfragen zu erhalten.", en_GB="Share your vehicle's current location with Alexa to get smarter responses for nearby restaurants, local\nweather and more.", es_ES="Comparte la ubicación actual de tu vehículo con Alexa para recibir respuestas más precisas respecto a\nrestaurantes cercanos, el tiempo local y más.", fr_FR="Partagez la localisation actuelle de votre véhicule avec Alexa pour obtenir des réponses plus pertinentes\nconcernant les restaurants à proximité, la météo locale et bien plus encore.", it_IT="Condividi la posizione attuale del tuo veicolo con Alexa per ottenere risposte più pertinenti sui ristoranti\nnelle vicinanze, sul meteo locale e molto altro.")
